# pip install jsonschema
import jsonschema

# The published tool schema (input_schema section)
TOOL_SCHEMA = {
    "type": "object",
    "properties": {
        "city": {"type": "string", "minLength": 1},
        "units": {"type": "string", "enum": ["metric", "imperial"]}
    },
    "required": ["city"],
    "additionalProperties": False
}

def dispatch_tool_call(tool_input: dict) -> dict:
    """Validate the agent's tool call input before invoking the implementation."""
    try:
        jsonschema.validate(instance=tool_input, schema=TOOL_SCHEMA)
    except jsonschema.ValidationError as e:
        # Return error details so the agent can self-correct
        return {"is_error": True, "content": f"Invalid tool call: {e.message}"}

    # Only reach here if validation passed
    return get_weather_impl(**tool_input)


def get_weather_impl(city: str, units: str = "metric") -> dict:
    # Real implementation would call a weather API
    return {"city": city, "temp": 18, "units": units, "condition": "partly cloudy"}


# Test valid call
result = dispatch_tool_call({"city": "London", "units": "metric"})
print(result)
# {'city': 'London', 'temp': 18, 'units': 'metric', 'condition': 'partly cloudy'}

# Test invalid call (missing required field)
result = dispatch_tool_call({"units": "metric"})
print(result)
# {'is_error': True, 'content': "Invalid tool call: 'city' is a required property"}

# Test invalid call (unknown field rejected by additionalProperties: false)
result = dispatch_tool_call({"city": "London", "country": "UK"})
print(result)
# {'is_error': True, 'content': 'Invalid tool call: Additional properties are not allowed...'}

# tools/search_flights/v1/schema.py  -- original contract, kept alive during migration
from pydantic import BaseModel, Field
from datetime import date


class SearchFlightsV1Input(BaseModel):
    origin: str = Field(description="IATA airport code for departure, e.g. 'LHR'")
    destination: str = Field(description="IATA airport code for arrival, e.g. 'JFK'")
    date: date = Field(description="Departure date in ISO-8601 format, e.g. '2025-06-15'")
    cabin_class: str = Field(
        default="economy",
        description="Cabin class: 'economy', 'business', or 'first'"
    )


# tools/search_flights/v2/schema.py  -- new version for multi-city itineraries
class SearchFlightsV2Input(BaseModel):
    origin: str = Field(description="IATA airport code for the first departure")
    destinations: list[str] = Field(
        description="List of IATA destination codes in itinerary order, e.g. ['JFK', 'LAX']",
        min_length=1
    )
    dates: list[date] = Field(
        description="Departure dates for each leg, one per destination",
        min_length=1
    )
    cabin_class: str = Field(
        default="economy",
        description="Cabin class: 'economy', 'business', or 'first'."
    )


# Tool registry that exposes both versions simultaneously
TOOL_REGISTRY = {
    "search_flights": {
        "description": "[DEPRECATED: prefer search_flights_v2] Search for a direct flight between two cities.",
        "input_schema": SearchFlightsV1Input.model_json_schema(),
        "handler": lambda inp: SearchFlightsV1Input.model_validate(inp)
    },
    "search_flights_v2": {
        "description": "Search for flights, including multi-city itineraries.",
        "input_schema": SearchFlightsV2Input.model_json_schema(),
        "handler": lambda inp: SearchFlightsV2Input.model_validate(inp)
    }
}


def dispatch(tool_name: str, tool_input: dict) -> dict:
    if tool_name not in TOOL_REGISTRY:
        return {"is_error": True, "content": f"Unknown tool: {tool_name}"}
    entry = TOOL_REGISTRY[tool_name]
    try:
        validated = entry["handler"](tool_input)
        return {"status": "ok", "validated_input": validated.model_dump()}
    except Exception as e:
        return {"is_error": True, "content": str(e)}


# Test dispatch with v1 call
print(dispatch("search_flights", {
    "origin": "LHR", "destination": "JFK", "date": "2025-08-10"
}))
# {'status': 'ok', 'validated_input': {'origin': 'LHR', 'destination': 'JFK',
#   'date': datetime.date(2025, 8, 10), 'cabin_class': 'economy'}}

# Test dispatch with v2 multi-city call
print(dispatch("search_flights_v2", {
    "origin": "LHR",
    "destinations": ["JFK", "LAX"],
    "dates": ["2025-08-10", "2025-08-15"]
}))
